parameters.body:
={
  "question": "Generate a JSON object with the following fields for this property:
1. "seo_description": A 2-sentence highly engaging marketing description.
2. "meta_title": A short, catchy title for SEO (under 60 chars).
3. "meta_description": A summary for search engines (under 160 chars).
4. "buyer_persona": The ideal target demographic (e.g., 'Luxury Host', 'First-time Buyer').
5. "competitiveness": Either 'High', 'Medium', or 'Low' based on the price point.

Property Details:
Title: {{ $json["body"]["title"] }}
Price: {{ $json["body"]["price"] }}
Bedrooms: {{ $json["body"]["bedrooms"] }}
Bathrooms: {{ $json["body"]["bathrooms"] }}
Location: {{ $json["body"]["parish"] }}
Description: {{ $json["body"]["description"] }}

Respond ONLY with valid JSON."
}

parameters.jsCode:
try {
  if ($input.all()[0].json.error) {
    throw new Error($input.all()[0].json.error);
  }

  const rawText = $input.all()[0].json.text;
  // Attempt to parse JSON from Flowise output block
  const jsonStr = rawText.replace(/```json\n?|```/g, '').trim();
  const parsed = JSON.parse(jsonStr);

  return {
    seo_description: parsed.seo_description || "Beautiful property in an excellent location.",
    meta_title: parsed.meta_title || "Premium Property Listing",
    meta_description: parsed.meta_description || "View this fantastic property on NextHome.",
    buyer_persona: parsed.buyer_persona || "General Buyer",
    competitiveness: parsed.competitiveness || "Medium"
  };
} catch (error) {
  // Fallback if AI fails or Flowise is unreachable
  const p = $node["Webhook: Enrich Property"].json.body;
  return {
    seo_description: `Fall in love with this stunning ${p.bedrooms || 1} bedroom property in ${p.parish || 'Jamaica'}. Immerse yourself in quality living.`,
    meta_title: `${p.title || 'Property'} | NextHome`,
    meta_description: `Explore this amazing real estate opportunity in ${p.parish || ''}. Contact us today.`,
    buyer_persona: "Value Seeker",
    competitiveness: "Fair"
  };
}
